#!/usr/bin/env python3
"""Poll Azure IMDS for spot eviction notice and trigger graceful shutdown.
Run as a daemon process on the Spot VM (e.g. systemd service).
"""
import time, requests, sys, subprocess, logging

IMDS_URL = "http://169.254.169.254/metadata/scheduledevents"
HEADERS = {"Metadata": "true"}
PARAMS = {"api-version": "2020-07-01"}
POLL_INTERVAL = 5  # seconds

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(message)s")

def approve_event(event_id: str, vm_name: str):
    """Acknowledge the event so Azure knows we're ready to be stopped."""
    body = {"StartRequests": [{"EventId": event_id}]}
    requests.post(
        "http://169.254.169.254/metadata/scheduledevents",
        json=body,
        headers=HEADERS,
        params=PARAMS,
    )
    logging.info(f"Approved eviction event {event_id} for {vm_name}")

def graceful_shutdown():
    logging.info("Eviction imminent. Starting graceful shutdown...")
    # Application-specific: flush queues, checkpoint ML training, drain HTTP
    subprocess.run(["systemctl", "stop", "my-worker-service"], check=False)
    logging.info("Worker stopped cleanly.")

def poll():
    while True:
        try:
            resp = requests.get(IMDS_URL, headers=HEADERS, params=PARAMS, timeout=3)
            events = resp.json().get("Events", [])
            for event in events:
                if event.get("EventType") == "Preempt":
                    vm_name = event.get("Resources", ["unknown"])[0]
                    logging.warning(f"Preempt event received for {vm_name}!")
                    graceful_shutdown()
                    approve_event(event["EventId"], vm_name)
                    sys.exit(0)
        except Exception as e:
            logging.error(f"IMDS poll error: {e}")
        time.sleep(POLL_INTERVAL)

if __name__ == "__main__":
    logging.info("Spot eviction watcher started.")
    poll()
